package main

import "fmt"

func main() {
    // With a number [3] -> Array (Fixed)
    // var myArray [3]string 

    // Empty brackets [] -> Slice (Dynamic!)
    var mySlice []string 

    // Creating a slice pre-filled with items
    scores := []int{90, 85, 100}

    fmt.Println(mySlice)
    fmt.Println(scores)
}
